  ollama = import ./ollama { inherit pkgs; };
  sshAgent = import ./ssh-agent {
    inherit config lib pkgs;
  };
  tmuxSessionLogger = import ./tmux-session-logger { inherit pkgs; };
in
[
  brewUpgrader
  cliproxyapi
  codeSyncer
  docker
  dockerPostgres
  dotfilesUpdater
  makeUpdater
  neversslKeepalive
  ollama
  sshAgent
  tmuxSessionLogger
]

